const now = new Date();
const hours = $.input.hoursAhead || 24;
const end = new Date(now.getTime() + hours * 60 * 60 * 1000);
return {
  timeMin: now.toISOString(),
  timeMax: end.toISOString(),
  today: now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })
};

const resp = $.steps.fetchEvents.response || {};
const items = resp.items || [];
const events = items.map((e, i) => {
  const start = e.start ? (e.start.dateTime || e.start.date || '') : '';
  const end = e.end ? (e.end.dateTime || e.end.date || '') : '';
  return {
    index: i + 1,
    summary: e.summary || 'No Title',
    start: start,
    end: end,
    location: e.location || '',
    description: (e.description || '').slice(0, 200),
    attendees: (e.attendees || []).map(a => a.email || '').filter(Boolean).slice(0, 5),
    hangoutLink: e.hangoutLink || e.conferenceData?.entryPoints?.[0]?.uri || ''
  };
});
let compiled = '';
events.forEach(e => {
  compiled += e.index + '. ' + e.summary + '\n';
  compiled += '   Time: ' + e.start + ' to ' + e.end + '\n';
  if (e.location) compiled += '   Location: ' + e.location + '\n';
  if (e.description) compiled += '   Details: ' + e.description + '\n';
  if (e.attendees.length > 0) compiled += '   Attendees: ' + e.attendees.join(', ') + '\n';
  if (e.hangoutLink) compiled += '   Meet: ' + e.hangoutLink + '\n';
  compiled += '\n';
});
return { events, compiled, count: events.length };

const d = $.steps.parseEvents.output;
const today = $.steps.buildTimeRange.output.today;
let prompt = 'You are a personal executive assistant. Create smart, actionable reminders for upcoming calendar events.\n\n';
prompt += 'TODAY: ' + today + '\n\n';
prompt += 'UPCOMING EVENTS (' + d.count + '):\n';
prompt += d.compiled + '\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Prioritize events by urgency and importance\n';
prompt += '- Add preparation tips for meetings\n';
prompt += '- Flag scheduling conflicts\n';
prompt += '- Suggest time blocks for preparation\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "dayOverview": "brief day overview",\n';
prompt += '  "reminders": [{\n';
prompt += '    "event": "event name",\n';
prompt += '    "time": "formatted time",\n';
prompt += '    "priority": "high|medium|low",\n';
prompt += '    "prepTip": "preparation suggestion",\n';
prompt += '    "reminder": "what to remember"\n';
prompt += '  }],\n';
prompt += '  "conflicts": ["any scheduling conflicts"],\n';
prompt += '  "freeSlots": ["available time blocks"]\n';
prompt += '}';
return { prompt };

let raw = $.steps.aiReminders.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { dayOverview: raw, reminders: [], conflicts: [], freeSlots: [] }; }

const ai = $.steps.parseAI.output;
const today = $.steps.buildTimeRange.output.today;
const reminders = ai.reminders || [];

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Daily Calendar Briefing', emoji: true } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*' + today + '*' } });

if (ai.dayOverview) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ai.dayOverview.slice(0, 500) } });
}

blocks.push({ type: 'divider' });

reminders.forEach(r => {
  let icon = ':white_circle:';
  if (r.priority === 'high') icon = ':red_circle:';
  if (r.priority === 'medium') icon = ':large_yellow_circle:';
  let text = icon + ' *' + (r.event || 'Event') + '* — ' + (r.time || '');
  if (r.prepTip) text += '\n_Prep:_ ' + r.prepTip;
  if (r.reminder) text += '\n_Note:_ ' + r.reminder;
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: text } });
});

const conflicts = ai.conflicts || [];
if (conflicts.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':warning: *Conflicts:* ' + conflicts.join(', ') } });
}

const freeSlots = ai.freeSlots || [];
if (freeSlots.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: ':clock3: *Free Slots:* ' + freeSlots.join(', ') } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Google Calendar + Claude AI' }] });

const fallback = 'Daily Briefing: ' + reminders.length + ' events for ' + today;
return { blocks, fallback };
